/* DSOP AO dashboard — vanilla JS single-page app. Reads site/data/*.json (regenerated by the
 * pipeline's body-of-evidence job; seed copies are committed so the site renders before CI). */
"use strict";

const DATA = {};
const FILES = ["meta", "summary", "controls", "findings", "poam", "conmon", "pipeline"];

async function loadAll() {
  await Promise.all(FILES.map(async f => {
    try { const r = await fetch(`data/${f}.json`, { cache: "no-store" }); DATA[f] = r.ok ? await r.json() : {}; }
    catch { DATA[f] = {}; }
  }));
}

const $ = s => document.querySelector(s);
const $$ = s => Array.from(document.querySelectorAll(s));
const esc = s => String(s ?? "").replace(/[&<>"]/g, c => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[c]));
const num = n => (n == null ? "—" : n);
const cls = r => (r === "Compliant" ? "Compliant" : r === "Non-Compliant" ? "Non-Compliant" :
  (r || "").startsWith("Not Applicable") ? "NotApplicable" : "NotReviewed");

/* ---- tabs ---- */
function initTabs() {
  $$("#tabs button").forEach(b => b.addEventListener("click", () => {
    $$("#tabs button").forEach(x => x.classList.toggle("active", x === b));
    $$(".tab").forEach(t => t.classList.toggle("active", t.id === "tab-" + b.dataset.tab));
    location.hash = b.dataset.tab;
  }));
  const h = (location.hash || "#status").slice(1);
  const btn = $(`#tabs button[data-tab="${h}"]`); if (btn) btn.click();
}

/* ---- header ---- */
function renderHeader() {
  const m = DATA.meta || {};
  if (m.system_name) $("#sys-name").textContent = `${m.system_name}${m.system_acronym ? " (" + m.system_acronym + ")" : ""} — Body of Evidence`;
  $("#sys-sub").textContent = `${m.categorization || "DevSecOps pipeline"} · RMF / cATO / Navy RAISE 2.0 · eMASS-ready evidence`;
  const a = $("#auth-status");
  a.textContent = "authorization: " + (m.authorization_status || "—");
  const lo = (m.authorization_status || "").toLowerCase();
  a.className = "badge " + (lo.includes("cato") || lo.includes("ato") && !lo.includes("not") ? "badge-ok" : lo.includes("condition") ? "badge-warn" : "badge-neutral");
  $("#gen-time").textContent = "generated: " + (DATA.summary?.generated || m.generated || "—");
  if (m.repo) {
    const [org, repo] = m.repo.includes("/") ? m.repo.split("/") : [null, null];
    $("#commit-line").innerHTML = (m.run_url ? `<a href="${esc(m.run_url)}">assessing run</a> · ` : "") +
      (m.sha ? `commit <code>${esc(m.sha.slice(0, 12))}</code>` : "") + (m.ref ? ` (${esc(m.ref)})` : "");
  }
}

/* ---- STATUS ---- */
function renderStatus() {
  const s = DATA.summary || {}; const c = s.controls || {}; const f = s.findings || {}; const p = s.poam || {};
  const bs = f.by_severity || {};
  const card = (val, lbl, kls, note) => `<div class="card ${kls || ""}"><div class="big">${num(val)}</div><div class="lbl">${esc(lbl)}</div>${note ? `<div class="note">${note}</div>` : ""}</div>`;
  const nr = c.not_reviewed ?? ((c.results && Object.entries(c.results).reduce((a, [k, v]) => a + (k.startsWith("Not Reviewed") ? v : 0), 0)) || 0);
  $("#status-cards").innerHTML = [
    card(c.compliant, "Controls compliant", "ok", `of ${num(c.total)} · auto-assess ${num(c.automated_assessment_coverage_pct)}%`),
    card(c.noncompliant, "Controls non-compliant", c.noncompliant ? "bad" : "ok"),
    card(nr, "Controls not reviewed", nr ? "warn" : "ok", "manual assessment by the SCA"),
    card(p.open, "POA&M open", p.open ? "warn" : "ok", `${num(p.overdue)} overdue · ${num(p.out_of_raise_scope)} out-of-RAISE-scope`),
    card((bs.critical || 0) + (bs.high || 0), "Findings Critical+High", (bs.critical || bs.high) ? "bad" : "ok", `🔴${num(bs.critical)} 🟠${num(bs.high)} 🟡${num(bs.medium)} 🔵${num(bs.low)}`),
    card(s.sbom_component_count, "SBOM components", "", "SPDX 2.3 + CycloneDX 1.5"),
    card(s.scorecard_overall != null ? s.scorecard_overall + "/10" : "—", "OpenSSF Scorecard", s.scorecard_overall != null ? (s.scorecard_overall >= 7 ? "ok" : s.scorecard_overall >= 4 ? "warn" : "bad") : ""),
    card((s.gates_executed || []).length, "Pipeline gates executed", "", esc((s.gates_executed || []).join(", ") || "—")),
  ].join("");

  // family bars
  const fams = c.by_family || {};
  $("#family-bars").innerHTML = Object.keys(fams).length ? Object.entries(fams).sort().map(([fam, v]) => {
    const tot = v.total || 1;
    const seg = (n, k) => n ? `<span class="seg ${k}" style="width:${(100 * n / tot).toFixed(1)}%"></span>` : "";
    return `<div class="bar"><span class="name">${esc(fam)}</span><span class="track">${seg(v.Compliant, "ok")}${seg(v["Non-Compliant"], "bad")}${seg(v["Not Reviewed"], "warn")}${seg(v["Not Applicable"], "na")}</span><span class="num">${v.Compliant || 0}✓ ${v["Non-Compliant"] || 0}✗ ${v["Not Reviewed"] || 0}? /${tot}</span></div>`;
  }).join("") : `<div class="empty">No control data yet — run the pipeline.</div>`;

  // RAISE gates
  const rg = s.raise_gates_status || [];
  $("#raise-gates").innerHTML = rg.length ? rg.map(g =>
    `<div class="gate-row"><span class="dot ${g.executed ? "on" : "off"}"></span><strong>Gate ${g.gate}</strong> — ${esc(g.name)} <span class="muted" style="margin-left:auto">${esc(g.satisfied_by)}</span></div>`).join("")
    : `<div class="empty">Run the pipeline to populate RAISE gate status.</div>`;
}

/* ---- CONTROLS ---- */
let CTLS = [];
function renderControlsTab() {
  CTLS = (DATA.controls?.controls) || [];
  const fams = [...new Set(CTLS.map(c => c.family))].sort();
  const sts = [...new Set(CTLS.map(c => c.implementation_status))].sort();
  $("#ctl-family").innerHTML = `<option value="">all families</option>` + fams.map(f => `<option>${esc(f)}</option>`).join("");
  $("#ctl-status").innerHTML = `<option value="">all implementation statuses</option>` + sts.map(s => `<option>${esc(s)}</option>`).join("");
  ["ctl-search", "ctl-family", "ctl-result", "ctl-status"].forEach(id => $("#" + id).addEventListener("input", drawControls));
  drawControls();
}
function drawControls() {
  const q = $("#ctl-search").value.toLowerCase(), fam = $("#ctl-family").value, res = $("#ctl-result").value, st = $("#ctl-status").value;
  const rows = CTLS.filter(c => {
    if (fam && c.family !== fam) return false;
    if (st && c.implementation_status !== st) return false;
    if (res) { if (res === "Not Reviewed") { if (!(c.test_result || "").startsWith("Not Reviewed")) return false; } else if (c.test_result !== res) return false; }
    if (q && !(`${c.id} ${c.title} ${c.narrative}`.toLowerCase().includes(q))) return false;
    return true;
  });
  $("#ctl-count").textContent = `${rows.length} / ${CTLS.length} controls`;
  $("#controls-list").innerHTML = rows.length ? rows.map(c => {
    const fc = c.related_finding_counts || {};
    const hc = (fc.critical || 0) + (fc.high || 0);
    const arts = (c.evidence_artifacts || []).map(a => `<code>${esc(a)}</code>`).join(" ");
    return `<details class="ctl"><summary>
      <span class="cid">${esc(c.id)}</span><span class="ctitle">${esc(c.title)}</span>
      <span class="tr-result ${cls(c.test_result)}">${esc(c.test_result)}</span>
      <span class="tag">${esc(c.implementation_status)}</span><span class="tag">${esc(c.responsibility)}</span>
      ${hc ? `<span class="sev high">${hc} H+/C</span>` : ""}
      ${(c.raise_gate || []).length ? `<span class="tag">RAISE ${(c.raise_gate).join(",")}</span>` : ""}
    </summary><div class="body">
      <p>${esc(c.narrative)}</p>
      <div class="kv">
        <span class="k">Test result rationale</span><span>${esc(c.test_result_rationale || "—")}</span>
        <span class="k">Assessing gate(s)</span><span>${(c.evidence_gates || []).map(g => `<span class="tag">${esc(g)}</span>`).join("") || "<em>manual / process</em>"}</span>
        <span class="k">Evidence artifact(s)</span><span>${arts || "—"}</span>
        <span class="k">Assessment methods</span><span>${(c.assessment_methods || []).join(", ") || "Examine; Test"}</span>
        <span class="k">CCIs</span><span class="mono">${(c.ccis || []).join(", ") || "—"}</span>
        <span class="k">SSDF</span><span>${(c.ssdf || []).join(", ") || "—"}</span>
        <span class="k">Inherited from</span><span>${esc(c.inherited_from || "—")}</span>
        <span class="k">Related findings</span><span>🔴${fc.critical || 0} 🟠${fc.high || 0} 🟡${fc.medium || 0} 🔵${fc.low || 0}</span>
        <span class="k">Last assessed</span><span>${esc(c.last_assessed || "—")} ${c.assessing_run ? `· <a href="${esc(c.assessing_run)}">run</a>` : ""}</span>
      </div>
    </div></details>`;
  }).join("") : `<div class="empty">No matching controls.</div>`;
}

/* ---- FINDINGS ---- */
let FNDS = [];
function renderFindingsTab() {
  FNDS = (DATA.findings?.findings) || [];
  const gates = [...new Set(FNDS.map(f => f.gate))].sort();
  const tools = [...new Set(FNDS.map(f => f.tool))].sort();
  $("#fnd-gate").innerHTML = `<option value="">all gates</option>` + gates.map(g => `<option>${esc(g)}</option>`).join("");
  $("#fnd-tool").innerHTML = `<option value="">all tools</option>` + tools.map(t => `<option>${esc(t)}</option>`).join("");
  ["fnd-search", "fnd-severity", "fnd-gate", "fnd-tool"].forEach(id => $("#" + id).addEventListener("input", drawFindings));
  drawFindings();
}
const SEVR = { critical: 4, high: 3, medium: 2, low: 1, info: 0 };
function drawFindings() {
  const q = $("#fnd-search").value.toLowerCase(), sv = $("#fnd-severity").value, gt = $("#fnd-gate").value, tl = $("#fnd-tool").value;
  let rows = FNDS.filter(f => (!sv || f.severity === sv) && (!gt || f.gate === gt) && (!tl || f.tool === tl) &&
    (!q || `${f.title} ${f.component || ""} ${f.location || ""} ${(f.cve || []).join(" ")} ${(f.cwe || []).join(" ")}`.toLowerCase().includes(q)));
  rows.sort((a, b) => (SEVR[b.severity] - SEVR[a.severity]) || a.gate.localeCompare(b.gate));
  $("#fnd-count").textContent = `${rows.length} / ${FNDS.length} findings`;
  const tb = $("#findings-table tbody");
  tb.innerHTML = rows.length ? rows.slice(0, 1500).map(f => `<tr>
    <td><span class="sev ${esc(f.severity)}">${esc(f.severity)}</span></td>
    <td>${esc(f.gate)}</td><td>${esc(f.tool)}</td>
    <td>${esc(f.title)}${f.run_url ? ` <a href="${esc(f.run_url)}" title="run">↗</a>` : ""}</td>
    <td class="mono">${esc(f.component ? f.component + (f.version ? "@" + f.version : "") : "")}${f.location ? `<br><span class="muted">${esc(f.location)}</span>` : ""}</td>
    <td class="mono">${esc((f.cve || []).join(" "))}${f.cve?.length && f.cwe?.length ? " · " : ""}${esc((f.cwe || []).join(" "))}</td>
    <td>${f.fix === "fixed" ? "✅ fix avail" : f.fix === "unfixed" ? "—" : ""}</td></tr>`).join("")
    : `<tr><td colspan="7"><div class="empty">No matching findings (or none yet — run the pipeline).</div></td></tr>`;
}

/* ---- POA&M ---- */
let PMS = [];
function renderPoamTab() {
  PMS = (DATA.poam?.items) || [];
  ["pm-search", "pm-cat"].forEach(id => $("#" + id).addEventListener("input", drawPoam));
  ["pm-overdue", "pm-oos"].forEach(id => $("#" + id).addEventListener("change", drawPoam));
  drawPoam();
}
function catOf(i) { const m = (i.severity_value || "").match(/CAT (I+)/); return m ? m[1] : ""; }
function drawPoam() {
  const q = $("#pm-search").value.toLowerCase(), cat = $("#pm-cat").value, od = $("#pm-overdue").checked, oos = $("#pm-oos").checked;
  let rows = PMS.filter(i => (!cat || catOf(i) === cat) && (!od || i.overdue) && (!oos || i.out_of_raise_scope) &&
    (!q || `${i.control_vulnerability_description} ${i.security_control_number} ${i.source_identifying_control_vulnerability}`.toLowerCase().includes(q)));
  $("#pm-count").textContent = `${rows.length} / ${PMS.length} POA&M items`;
  $("#poam-list").innerHTML = rows.length ? rows.map(i => {
    const c = catOf(i);
    const desc = (i.control_vulnerability_description || "").split("\n")[0];
    return `<details class="pm cat-${c || "III"} ${i.overdue ? "overdue" : ""}"><summary>
      <strong class="mono">${esc(i.security_control_number)}</strong>
      <span class="sev ${c === "I" ? "high" : c === "II" ? "medium" : "low"}">${esc(i.severity_value)}</span>
      <span style="flex:1;min-width:160px">${esc(desc)}</span>
      <span class="muted">due ${esc(i.scheduled_completion_date)}</span>
      ${i.overdue ? `<span class="flag od">OVERDUE</span>` : ""}${i.out_of_raise_scope ? `<span class="flag oos">OUT-OF-RAISE-SCOPE</span>` : ""}
    </summary>
    <div class="body" style="padding:8px 12px">
      <div class="kv">
        <span class="k">Description</span><span>${esc(i.control_vulnerability_description)}</span>
        <span class="k">Source</span><span>${esc(i.source_identifying_control_vulnerability)}</span>
        <span class="k">CCIs</span><span class="mono">${esc(i.security_checks_ccis || "—")}</span>
        <span class="k">Raw / adjusted severity</span><span>${esc(i.raw_severity)} / ${esc(i.severity_value)}</span>
        <span class="k">Residual risk</span><span>${esc(i.residual_risk_level)}</span>
        <span class="k">Scheduled completion</span><span>${esc(i.scheduled_completion_date)} ${i.overdue ? `<span class="flag od">OVERDUE</span>` : ""} (first seen ${esc(i.first_seen)}, age ${num(i.age_days)}d)</span>
        <span class="k">Milestones</span><span>${(i.milestones || []).map(m => `${esc(m.description)} → ${esc(m.date)}`).join("<br>")}</span>
        <span class="k">Recommendations</span><span>${esc(i.recommendations)}</span>
        <span class="k">Mitigations</span><span>${esc(i.mitigations)}</span>
        <span class="k">Comments</span><span>${esc(i.comments || "—")}</span>
        <span class="k">POC / Office</span><span>${esc(i.point_of_contact)} · ${esc(i.office_org)}</span>
      </div>
    </div></details>`;
  }).join("") : `<div class="empty">No matching POA&M items (or none above threshold — clean run!).</div>`;
}

/* ---- CONMON ---- */
function renderConmon() {
  const snaps = (DATA.conmon?.snapshots) || [];
  const chart = $("#conmon-chart");
  if (!snaps.length) { chart.innerHTML = `<div class="empty">No snapshots yet — each pipeline run adds one.</div>`; }
  else {
    const max = Math.max(1, ...snaps.map(s => { const b = s.findings_by_severity || {}; return (b.critical || 0) + (b.high || 0) + (b.medium || 0) + (b.low || 0); }));
    const px = n => Math.max(0, Math.round(110 * n / max));
    chart.innerHTML = snaps.slice(-90).map(s => { const b = s.findings_by_severity || {}; return `<div class="col" title="${esc(s.date)}">
      <i class="low" style="height:${px(b.low || 0)}px"></i><i class="medium" style="height:${px(b.medium || 0)}px"></i><i class="high" style="height:${px(b.high || 0)}px"></i><i class="critical" style="height:${px(b.critical || 0)}px"></i>
    </div>`; }).join("");
  }
  const tb = $("#conmon-table tbody");
  tb.innerHTML = snaps.length ? snaps.slice().reverse().map(s => { const b = s.findings_by_severity || {}, c = s.controls_results || {}, k = s.poam_by_cat || {}; return `<tr>
    <td>${esc(s.date)}</td><td>${b.critical || 0}/${b.high || 0}/${b.medium || 0}/${b.low || 0}</td>
    <td>${c.Compliant || 0}/${c["Non-Compliant"] || 0}</td><td>${num(s.controls_automated_coverage_pct)}%</td>
    <td>${num(s.poam_open)} (${num(s.poam_overdue)})</td><td>${k.I || 0}/${k.II || 0}/${k.III || 0}</td>
    <td>${num(s.sbom_component_count)}</td><td>${s.run_url ? `<a href="${esc(s.run_url)}">${esc((s.commit || "").slice(0, 8)) || "run"}</a>` : esc((s.commit || "").slice(0, 8))}</td></tr>`; }).join("")
    : `<tr><td colspan="8"><div class="empty">No snapshots.</div></td></tr>`;
}

/* ---- PIPELINE ---- */
function renderPipeline() {
  const gates = (DATA.pipeline?.gates) || [];
  $("#pipeline-table tbody").innerHTML = gates.length ? gates.map(g => `<tr>
    <td><strong>${esc(g.id)}</strong><br><span class="muted">${esc(g.name)}</span></td>
    <td>${esc(g.phase)}</td><td>${(g.tools || []).map(t => `<span class="tag">${esc(t)}</span>`).join(" ")}</td>
    <td>${(g.raise_gate || []).length ? (g.raise_gate).join(", ") : "—"}</td>
    <td class="mono">${(g.controls_evidenced || []).join(", ") || "—"}</td>
    <td>${g.executed ? "✅" : "—"}</td><td>${num(g.finding_count)}</td>
    <td class="muted">${esc(g.fail_policy || "")}</td></tr>`).join("")
    : `<tr><td colspan="8"><div class="empty">No pipeline data — run the pipeline.</div></td></tr>`;
}

/* ---- PACKAGE ---- */
function renderPackage() {
  const m = DATA.meta || {};
  if (m.repo && m.repo.includes("/")) {
    const url = `https://github.com/${m.repo}`;
    $("#pkg-links").innerHTML = `Latest: <a href="${url}/releases/latest">latest GitHub Release</a> (look for <code>emass-package.zip</code>) ·
      <a href="${url}/actions">pipeline runs</a> (download the <code>body-of-evidence</code> / <code>emass-package</code> artifact) ·
      <a href="${url}/tree/${esc(m.ref || "main")}/compliance">compliance/ in the repo</a>`;
  } else {
    $("#pkg-links").innerHTML = `<span class="muted">(Set the repo in the catalog metadata; the eMASS package is attached to GitHub Releases and to the <code>body-of-evidence</code> workflow artifact.)</span>`;
  }
}

/* ---- boot ---- */
(async function () {
  await loadAll();
  renderHeader(); renderStatus(); renderControlsTab(); renderFindingsTab(); renderPoamTab(); renderConmon(); renderPipeline(); renderPackage();
  initTabs();
})();
